30	// Recursively walk the parsed YAML tree looking for secret key names.
31	// Arrays are traversed element-by-element; plain objects have all their keys checked.
32	// The recursion does NOT conflate object keys (like "slot") with the secret-key set.
33	function findSecretKey(node: unknown): string | undefined {
34	  if (node === null || typeof node !== 'object') return undefined;
35	  if (Array.isArray(node)) {
36	    for (const item of node) {
37	      const found = findSecretKey(item);
38	      if (found !== undefined) return found;
39	    }
40	    return undefined;
41	  }
42	  const obj = node as Record<string, unknown>;
43	  for (const key of Object.keys(obj)) {
44	    if (SECRET_KEYS.has(key)) return key;
45	    const found = findSecretKey(obj[key]);
46	    if (found !== undefined) return found;
47	  }
