1	import { describe, it, expect } from 'vitest';
2	import { parseSkillManifest } from '../manifest.js';
3	
4	const SAMPLE_OK = `name: github
5	description: Access the GitHub REST API with a personal access token.
6	version: 1
7	capabilities:
8	  allowedHosts:
9	    - api.github.com
10	  credentials:
11	    - slot: GITHUB_TOKEN
12	      kind: api-key
13	      description: GitHub PAT.
14	`;
15	
16	describe('parseSkillManifest', () => {
17	  it('accepts a well-formed manifest', () => {
18	    const r = parseSkillManifest(SAMPLE_OK);
19	    expect(r.ok).toBe(true);
20	    if (!r.ok) return;
21	    expect(r.value.id).toBe('github');
22	    expect(r.value.description).toMatch(/GitHub/);
23	    expect(r.value.version).toBe(1);
24	    expect(r.value.capabilities.allowedHosts).toEqual(['api.github.com']);
25	    expect(r.value.capabilities.credentials).toEqual([
26	      { slot: 'GITHUB_TOKEN', kind: 'api-key', description: 'GitHub PAT.' },
27	    ]);
28	  });
29	
30	  it('defaults version to 0 when absent', () => {
31	    const r = parseSkillManifest(`name: x\ndescription: x desc`);
32	    expect(r.ok).toBe(true);
33	    if (r.ok) expect(r.value.version).toBe(0);
34	  });
35	
36	  it('rejects name not matching kebab-case-ish regex', () => {
37	    for (const bad of ['GitHub', '_github', '0github', 'a'.repeat(65)]) {
38	      const r = parseSkillManifest(`name: ${bad}\ndescription: x`);
39	      expect(r.ok).toBe(false);
40	      if (!r.ok) expect(r.code).toBe('invalid-name');
41	    }
42	  });
43	
44	  it('rejects description over 240 chars', () => {
45	    const r = parseSkillManifest(`name: ok\ndescription: ${'x'.repeat(241)}`);
46	    expect(r.ok).toBe(false);
47	    if (!r.ok) expect(r.code).toBe('invalid-description');
48	  });
49	
50	  it('rejects allowedHosts with scheme / path / wildcard / IP literal', () => {
51	    for (const bad of [
52	      'https://api.github.com',
53	      'api.github.com/foo',
54	      '*.github.com',
55	      '192.168.1.1',
56	    ]) {
57	      const r = parseSkillManifest(
58	        `name: x\ndescription: x\ncapabilities:\n  allowedHosts: [${bad}]\n  credentials: []`,
