1	import { makeAgentContext, PluginError, isRejection, type AgentContext, type HookBus } from '@ax/core';
2	import { z } from 'zod';
3	import type {
4	  SkillsListOutput,
5	  SkillsGetOutput,
6	  SkillsUpsertInput,
7	  SkillsUpsertOutput,
8	} from './types.js';
9	
10	// ---------------------------------------------------------------------------
11	// /admin/skills* CRUD handlers (admin-only).
12	//
13	// Routes:
14	//   GET    /admin/skills            → list skill summaries
15	//   GET    /admin/skills/:id        → get full skill detail
16	//   POST   /admin/skills            → create (or upsert) from full SKILL.md
17	//   PUT    /admin/skills/:id        → update from full SKILL.md
18	//   DELETE /admin/skills/:id        → delete (409 if in-use)
19	//
20	// Shared plumbing copied locally per Invariant I2 (no cross-plugin imports):
21	//   - RouteRequest / RouteResponse / AuthedUser interfaces
22	//   - ADMIN_BODY_MAX_BYTES
23	//   - requireAuthenticated / requireAdmin
24	//   - parseRequestBody
25	//   - writeServiceError (skills-specific error codes)
26	// ---------------------------------------------------------------------------
27	
28	// ---------------------------------------------------------------------------
29	// Duck-typed route plumbing (copied from @ax/credentials-admin-routes/shared.ts
30	// — do NOT import that package, Invariant I2 forbids cross-plugin imports).
31	// ---------------------------------------------------------------------------
32	
33	export const ADMIN_BODY_MAX_BYTES = 64 * 1024;
34	
35	export interface RouteRequest {
36	  readonly headers: Record<string, string>;
37	  readonly body: Buffer;
38	  readonly cookies: Record<string, string>;
39	  readonly query: Record<string, string>;
40	  readonly params: Record<string, string>;
41	  signedCookie(name: string): string | null;
42	}
43	
44	export interface RouteResponse {
45	  status(n: number): RouteResponse;
46	  json(v: unknown): void;
47	  text(s: string): void;
48	  end(): void;
49	}
50	
51	export interface AuthedUser {
52	  id: string;
53	  isAdmin: boolean;
54	}
55	
56	export async function requireAuthenticated(
57	  bus: HookBus,
58	  ctx: AgentContext,
59	  req: RouteRequest,
60	  res: RouteResponse,
61	): Promise<AuthedUser | null> {
62	  try {
63	    const result = await bus.call<
64	      { req: RouteRequest },
65	      { user: { id: string; isAdmin: boolean } }
66	    >('auth:require-user', ctx, { req });
67	    return { id: result.user.id, isAdmin: result.user.isAdmin };
68	  } catch (err) {
69	    if (err instanceof PluginError || isRejection(err)) {
70	      res.status(401).json({ error: 'unauthenticated' });
71	      return null;
72	    }
73	    throw err;
74	  }
75	}
76	
77	export async function requireAdmin(
78	  bus: HookBus,
79	  ctx: AgentContext,
80	  req: RouteRequest,
81	  res: RouteResponse,
82	): Promise<AuthedUser | null> {
83	  const actor = await requireAuthenticated(bus, ctx, req, res);
84	  if (actor === null) return null;
85	  if (!actor.isAdmin) {
86	    res.status(403).json({ error: 'forbidden' });
87	    return null;
88	  }
89	  return actor;
90	}
91	
92	export type ParseBodyResult =
93	  | { ok: true; value: unknown }
94	  | { ok: false; status: 400 | 413; message: string };
95	
96	export function parseRequestBody(body: Buffer): ParseBodyResult {
97	  if (body.length > ADMIN_BODY_MAX_BYTES) {
98	    return { ok: false, status: 413, message: 'body-too-large' };
99	  }
100	  if (body.length === 0) return { ok: true, value: {} };
101	  try {
102	    return { ok: true, value: JSON.parse(body.toString('utf8')) };
103	  } catch {
104	    return { ok: false, status: 400, message: 'invalid-json' };
105	  }
106	}
107	
108	// ---------------------------------------------------------------------------
109	// Skills-specific PluginError -> HTTP status mapping
110	// ---------------------------------------------------------------------------
111	
112	export function writeServiceError(res: RouteResponse, err: unknown): boolean {
113	  if (err instanceof PluginError) {
114	    if (err.code === 'skill-not-found') {
115	      res.status(404).json({ error: err.message });
116	      return true;
117	    }
118	    if (err.code === 'skill-in-use') {
119	      res.status(409).json({ error: err.message, code: 'skill-in-use' });
120	      return true;
121	    }
122	    const badRequestCodes = new Set([
123	      'invalid-name',
124	      'invalid-description',
125	      'invalid-host',
126	      'invalid-slot',
127	      'duplicate-slot',
128	      'invalid-kind',
129	      'invalid-yaml',
130	      'invalid-manifest',
131	      'invalid-version',
132	      'inline-secret-forbidden',
133	      'capability-deferred',
134	      'invalid-payload',
135	      'default-attached-requires-no-credentials',
136	    ]);
137	    if (badRequestCodes.has(err.code)) {
138	      res.status(400).json({ error: err.message, code: err.code });
139	      return true;
140	    }
141	  }
142	  return false;
143	}
144	
145	// ---------------------------------------------------------------------------
146	// Body schema
147	// ---------------------------------------------------------------------------
148	
149	const SKILL_MD_MAX = 32 * 1024;
150	
151	const upsertBodySchema = z
152	  .object({
153	    skillMd: z.string().min(1).max(SKILL_MD_MAX),
154	    defaultAttached: z.boolean().optional(),
155	  })
156	  .strict();
157	
158	// ---------------------------------------------------------------------------
159	// SKILL.md splitter
160	//
161	// Expects: ---\n<frontmatter>\n---\n<body> (body optional).
162	// Returns null if the fence pair is absent.
163	// ---------------------------------------------------------------------------
164	
165	function splitSkillMd(
166	  skillMd: string,
167	): { manifestYaml: string; bodyMd: string } | null {
168	  // Accept both LF and CRLF line endings on every fence boundary so a
169	  // SKILL.md authored / copy-pasted on Windows doesn't 400 here.
170	  const re = /^---\r?\n([\s\S]*?)\r?\n---(?:\r?\n([\s\S]*)|$)/;
171	  const m = re.exec(skillMd);
172	  if (m === null) return null;
173	  return { manifestYaml: m[1] ?? '', bodyMd: m[2] ?? '' };
174	}
175	
176	// ---------------------------------------------------------------------------
177	// Handlers
178	// ---------------------------------------------------------------------------
179	
180	const PLUGIN_NAME = '@ax/skills';
181	
182	export interface AdminRouteDeps {
183	  bus: HookBus;
184	}
185	
186	export function createAdminSkillsHandlers(deps: AdminRouteDeps): {
187	  list: (req: RouteRequest, res: RouteResponse) => Promise<void>;
188	  get: (req: RouteRequest, res: RouteResponse) => Promise<void>;
189	  create: (req: RouteRequest, res: RouteResponse) => Promise<void>;
190	  update: (req: RouteRequest, res: RouteResponse) => Promise<void>;
191	  destroy: (req: RouteRequest, res: RouteResponse) => Promise<void>;
192	} {
193	  const ctx = makeAgentContext({
194	    sessionId: 'skills-admin',
195	    agentId: PLUGIN_NAME,
196	    userId: 'admin',
197	  });
198	
199	  return {
200	    /** GET /admin/skills */
201	    async list(req: RouteRequest, res: RouteResponse): Promise<void> {
202	      const actor = await requireAdmin(deps.bus, ctx, req, res);
203	      if (actor === null) return;
204	      try {
205	        const out = await deps.bus.call<Record<string, never>, SkillsListOutput>(
206	          'skills:list',
207	          ctx,
208	          {},
209	        );
210	        res.status(200).json(out);
211	      } catch (err) {
212	        if (writeServiceError(res, err)) return;
213	        throw err;
214	      }
215	    },
216	
217	    /** GET /admin/skills/:id */
218	    async get(req: RouteRequest, res: RouteResponse): Promise<void> {
219	      const actor = await requireAdmin(deps.bus, ctx, req, res);
220	      if (actor === null) return;
221	      const { id } = req.params;
222	      if (!id) {
223	        res.status(400).json({ error: 'missing skill id' });
224	        return;
225	      }
226	      try {
227	        const detail = await deps.bus.call<{ skillId: string }, SkillsGetOutput>(
228	          'skills:get',
229	          ctx,
230	          { skillId: id },
231	        );
232	        res.status(200).json(detail);
233	      } catch (err) {
234	        if (writeServiceError(res, err)) return;
235	        throw err;
236	      }
237	    },
238	
239	    /** POST /admin/skills */
240	    async create(req: RouteRequest, res: RouteResponse): Promise<void> {
241	      const actor = await requireAdmin(deps.bus, ctx, req, res);
242	      if (actor === null) return;
243	
244	      const parsedBody = parseRequestBody(req.body);
245	      if (!parsedBody.ok) {
246	        res.status(parsedBody.status).json({ error: parsedBody.message });
247	        return;
248	      }
249	
250	      const zodResult = upsertBodySchema.safeParse(parsedBody.value);
251	      if (!zodResult.success) {
252	        const first = zodResult.error.issues[0];
253	        res.status(400).json({
254	          error:
255	            first?.message !== undefined && first.message.length > 0
256	              ? first.message
257	              : 'invalid-payload',
258	        });
259	        return;
260	      }
261	
262	      const split = splitSkillMd(zodResult.data.skillMd);
263	      if (split === null) {
264	        res.status(400).json({ error: 'missing frontmatter fence' });
265	        return;
266	      }
267	
268	      try {
269	        const out = await deps.bus.call<SkillsUpsertInput, SkillsUpsertOutput>(
270	          'skills:upsert',
271	          ctx,
272	          { ...split, defaultAttached: zodResult.data.defaultAttached ?? false },
273	        );
274	        res.status(201).json({ skillId: out.skillId, created: out.created });
275	      } catch (err) {
276	        if (writeServiceError(res, err)) return;
277	        throw err;
278	      }
279	    },
280	
281	    /** PUT /admin/skills/:id */
282	    async update(req: RouteRequest, res: RouteResponse): Promise<void> {
283	      const actor = await requireAdmin(deps.bus, ctx, req, res);
284	      if (actor === null) return;
285	
286	      const { id } = req.params;
287	      if (!id) {
288	        res.status(400).json({ error: 'missing skill id' });
289	        return;
290	      }
291	
292	      const parsedBody = parseRequestBody(req.body);
293	      if (!parsedBody.ok) {
294	        res.status(parsedBody.status).json({ error: parsedBody.message });
295	        return;
296	      }
297	
298	      const zodResult = upsertBodySchema.safeParse(parsedBody.value);
299	      if (!zodResult.success) {
300	        const first = zodResult.error.issues[0];
301	        res.status(400).json({
302	          error:
303	            first?.message !== undefined && first.message.length > 0
304	              ? first.message
305	              : 'invalid-payload',
306	        });
307	        return;
308	      }
309	
310	      const split = splitSkillMd(zodResult.data.skillMd);
311	      if (split === null) {
312	        res.status(400).json({ error: 'missing frontmatter fence' });
313	        return;
314	      }
315	
316	      // Quick name extraction to validate path-vs-manifest consistency
317	      // before the round-trip. The full parse happens inside skills:upsert
318	      // and the post-call equality check below is the source of truth;
319	      // this is just to give the caller a crisper 4xx without taking the
320	      // round-trip. Accepts unquoted, single-quoted, and double-quoted
321	      // scalars with optional trailing comments — same surface yaml itself
322	      // would accept.
323	      const nameMatch =
324	        /^\s*name\s*:\s*(?:"([^"\r\n]+)"|'([^'\r\n]+)'|([^\s#\r\n]+))\s*(?:#.*)?$/m.exec(
325	          split.manifestYaml,
326	        );
327	      const skillIdFromManifest =
328	        nameMatch?.[1] ?? nameMatch?.[2] ?? nameMatch?.[3];
329	      if (skillIdFromManifest !== undefined && skillIdFromManifest !== id) {
330	        res
331	          .status(400)
332	          .json({ error: 'skill id in path does not match manifest name' });
333	        return;
334	      }
335	
336	      try {
337	        const out = await deps.bus.call<SkillsUpsertInput, SkillsUpsertOutput>(
338	          'skills:upsert',
339	          ctx,
340	          { ...split, defaultAttached: zodResult.data.defaultAttached ?? false },
341	        );
342	
343	        // Double-check after the parse in case our quick regex missed something.
344	        if (out.skillId !== id) {
345	          res
346	            .status(400)
347	            .json({ error: 'skill id in path does not match manifest name' });
348	          return;
349	        }
350	
351	        res.status(200).json({ skillId: out.skillId, created: out.created });
352	      } catch (err) {
353	        if (writeServiceError(res, err)) return;
354	        throw err;
355	      }
356	    },
357	
358	    /** DELETE /admin/skills/:id */
359	    async destroy(req: RouteRequest, res: RouteResponse): Promise<void> {
360	      const actor = await requireAdmin(deps.bus, ctx, req, res);
361	      if (actor === null) return;
362	
363	      const { id } = req.params;
364	      if (!id) {
365	        res.status(400).json({ error: 'missing skill id' });
366	        return;
367	      }
368	
369	      try {
370	        await deps.bus.call<{ skillId: string }, Record<string, never>>(
371	          'skills:delete',
372	          ctx,
373	          { skillId: id },
374	        );
375	        res.status(204).end();
376	      } catch (err) {
377	        if (writeServiceError(res, err)) return;
378	        throw err;
379	      }
380	    },
381	  };
382	}
383	
384	// ---------------------------------------------------------------------------
385	// Route registration
386	// ---------------------------------------------------------------------------
387	
388	export async function registerAdminSkillsRoutes(
389	  bus: HookBus,
390	  initCtx: AgentContext,
391	): Promise<Array<() => void>> {
392	  const handlers = createAdminSkillsHandlers({ bus });
393	  const routes: Array<{
394	    method: 'GET' | 'POST' | 'PUT' | 'DELETE';
395	    path: string;
396	    handler: (req: RouteRequest, res: RouteResponse) => Promise<void>;
397	  }> = [
398	    { method: 'GET', path: '/admin/skills', handler: handlers.list },
399	    { method: 'GET', path: '/admin/skills/:id', handler: handlers.get },
400	    { method: 'POST', path: '/admin/skills', handler: handlers.create },
401	    { method: 'PUT', path: '/admin/skills/:id', handler: handlers.update },
402	    { method: 'DELETE', path: '/admin/skills/:id', handler: handlers.destroy },
403	  ];
404	  const unregisters: Array<() => void> = [];
405	  for (const route of routes) {
406	    const result = await bus.call<unknown, { unregister: () => void }>(
407	      'http:register-route',
408	      initCtx,
409	      route,
410	    );
411	    unregisters.push(result.unregister);
412	  }
413	  return unregisters;
414	}
