1	// ---------------------------------------------------------------------------
2	// installed-skills — materialize AX_INSTALLED_SKILLS_JSON at runner boot.
3	//
4	// K8s pods can't have the host write files into them at create-time, so the
5	// sandbox-k8s plugin passes installed-skill content as AX_INSTALLED_SKILLS_JSON
6	// (JSON-encoded array). The runner reads it from process.env BEFORE the SDK
7	// spawns and writes each skill's SKILL.md to
8	// $CLAUDE_CONFIG_DIR/skills/<id>/SKILL.md, then chmods the parent dir to
9	// 0555 so the runner's own tool calls can't extend or overwrite it.
10	//
11	// This is the symmetric peer of sandbox-subprocess's in-process
12	// materialization (open-session.ts). The two providers' on-disk shape after
13	// open-session is identical; only the transport differs (file write vs. env
14	// var).
15	//
16	// The env var is consumed BY THIS MODULE — it is NOT forwarded into the SDK
17	// subprocess (not in ENV_ALLOWLIST in proxy-startup.ts). Forwarding it would
18	// put the full skill content into every SDK call's env unnecessarily.
19	// ---------------------------------------------------------------------------
20	
21	import { promises as fs } from 'node:fs';
22	import * as path from 'node:path';
23	
24	const SKILL_ID_RE = /^[a-z][a-z0-9-]{0,63}$/;
25	
26	export async function materializeInstalledSkillsFromEnv(): Promise<void> {
27	  const json = process.env['AX_INSTALLED_SKILLS_JSON'];
28	  if (typeof json !== 'string' || json.length === 0) return;
29	
30	  const ccd = process.env['CLAUDE_CONFIG_DIR'];
31	  if (typeof ccd !== 'string' || ccd.length === 0) {
32	    throw new Error('AX_INSTALLED_SKILLS_JSON set but CLAUDE_CONFIG_DIR missing');
33	  }
34	
35	  let parsed: unknown;
36	  try {
37	    parsed = JSON.parse(json);
38	  } catch {
39	    throw new Error('AX_INSTALLED_SKILLS_JSON is not valid JSON');
40	  }
41	
42	  if (!Array.isArray(parsed)) {
43	    throw new Error('AX_INSTALLED_SKILLS_JSON must be an array');
44	  }
45	
46	  // Empty array: nothing to materialize, nothing to lock. The Phase 0
47	  // sandbox init container already created the skills dir at 0o755;
48	  // chmodding it (or creating it just to chmod it) would surface an
49	  // ENOENT on tmpdir-based tests AND would lock a dir we never touched
50	  // in prod. Early-return — same Phase 0 default behavior.
51	  if (parsed.length === 0) return;
52	
53	  const skillsDir = path.join(ccd, 'skills');
54	  await fs.mkdir(skillsDir, { recursive: true, mode: 0o755 });
55	  for (const entry of parsed) {
56	    if (
57	      typeof entry !== 'object' ||
