56	interface CredentialRow {
57	  scope: 'global' | 'user' | 'agent';
58	  ownerId: string | null;
59	  ref: string;
60	}
61	
62	async function purgeSkillCredentials(
63	  bus: HookBus,
64	  ctx: AgentContext,
65	  skillId: string,
66	  slots: string[],
67	): Promise<void> {
68	  if (slots.length === 0) return;
69	  if (!bus.hasService('credentials:list') || !bus.hasService('credentials:delete')) return;
70	
71	  const refsToDelete = new Set(slots.map((s) => `skill:${skillId}:${s}`));
72	  const { credentials } = await bus.call<
73	    Record<string, never>,
74	    { credentials: CredentialRow[] }
75	  >('credentials:list', ctx, {});
76	
77	  for (const c of credentials) {
78	    if (!refsToDelete.has(c.ref)) continue;
79	    // Per-row try/catch: one failed delete must not abort the rest. The caller
80	    // wraps the whole purge in its own try/catch for the list-phase errors.
81	    try {
82	      await bus.call<CredentialRow, void>('credentials:delete', ctx, {
83	        scope: c.scope,
84	        ownerId: c.ownerId,
85	        ref: c.ref,
86	      });
87	    } catch (err) {
88	      ctx.logger.warn('skills_purge_credential_delete_failed', {
89	        ref: c.ref,
90	        scope: c.scope,
91	        ownerId: c.ownerId,
92	        err: err instanceof Error ? err.message : String(err),
93	      });
94	    }
95	  }
96	}
