       >('skills:check-for-updates', ctx, { skillId: id });
       res.status(200).json(out);
     } catch (err) {
       if (writeServiceError(res, err)) return;
       throw err;
     }
   },

   /** POST /admin/skills/:id/refresh-from-source — convenience: check + if available, upsert. */
   async refresh(req: RouteRequest, res: RouteResponse): Promise<void> {
     const actor = await requireAdmin(deps.bus, ctx, req, res);
     if (actor === null) return;
     const { id } = req.params;
     if (!id) {
       res.status(400).json({ error: 'missing skill id' });
       return;
     }
     try {
       const check = await deps.bus.call<
         { skillId: string },
         SkillsCheckForUpdatesOutput
       >('skills:check-for-updates', ctx, { skillId: id });
       if (!check.available || check.latestSkillMd === undefined) {
         res.status(200).json({ updated: false, currentVersion: check.currentVersion });
         return;
       }
       // Re-use the splitter so /refresh follows the same upsert path as /create.
       const split = splitSkillMd(check.latestSkillMd);
       if (split === null) {
         res.status(502).json({ error: 'remote skill missing frontmatter fence' });
         return;
       }
       await deps.bus.call<SkillsUpsertInput, SkillsUpsertOutput>(
         'skills:upsert',
         ctx,
         { ...split },
       );
       res.status(200).json({ updated: true, newVersion: check.latestVersion });
     } catch (err) {
       if (writeServiceError(res, err)) return;
       throw err;
     }
   },
   ```
2. Update the handler return-type signature at the top of `createAdminSkillsHandlers` to include the two new handlers.
3. Import `SkillsCheckForUpdatesOutput` from `./types.js` at the top.
4. Add the two new routes to the `routes` array in `registerAdminSkillsRoutes` (around line 397-403):
   ```typescript
   { method: 'POST', path: '/admin/skills/:id/check-update', handler: handlers.checkUpdate },
   { method: 'POST', path: '/admin/skills/:id/refresh-from-source', handler: handlers.refresh },
   ```

### Step C.14 — Admin route tests

In `packages/skills/src/__tests__/admin-routes.test.ts`, append (inside the existing `describe(...)`):

```typescript
it('POST /admin/skills/:id/check-update returns the hook output (no sourceUrl → available:false)', async () => {
  const h = await makeHarness();
  const handlers = createAdminSkillsHandlers({ bus: h.bus });

  // Create a skill with NO sourceUrl
  const skillMd = `---\nname: nosrc\ndescription: nosrc\nversion: 1\n---\nbody`;
  await handlers.create(mkReq({ body: { skillMd } }), mkRes().res);

  const { res, statusOf, bodyOf } = mkRes();
  await handlers.checkUpdate(mkReq({ params: { id: 'nosrc' } }), res);
  expect(statusOf()).toBe(200);
  const body = bodyOf() as { available: boolean; currentVersion: number };
  expect(body.available).toBe(false);
  expect(body.currentVersion).toBe(1);
});

it('POST /admin/skills/:id/check-update returns 404 when skill does not exist', async () => {
  const h = await makeHarness();
  const handlers = createAdminSkillsHandlers({ bus: h.bus });
  const { res, statusOf } = mkRes();
  await handlers.checkUpdate(mkReq({ params: { id: 'missing' } }), res);
  expect(statusOf()).toBe(404);
});

it('POST /admin/skills/:id/refresh-from-source returns updated:false when sourceUrl is not set', async () => {
  const h = await makeHarness();
  const handlers = createAdminSkillsHandlers({ bus: h.bus });

  const skillMd = `---\nname: nosrc2\ndescription: nosrc\nversion: 1\n---\nbody`;
  await handlers.create(mkReq({ body: { skillMd } }), mkRes().res);

  const { res, statusOf, bodyOf } = mkRes();
  await handlers.refresh(mkReq({ params: { id: 'nosrc2' } }), res);
  expect(statusOf()).toBe(200);
  const body = bodyOf() as { updated: boolean; currentVersion: number };
  expect(body.updated).toBe(false);
  expect(body.currentVersion).toBe(1);
});
```

For test cases that need an actual remote fetch, write a separate test that stubs the hook directly by registering a replacement service handler. Look at the existing admin-routes.test.ts test for `skills:list` mocking (around line 1-200) for the pattern, OR look at how `plugin.test.ts` already harnesses the bus.

Add at least one positive test that exercises both the `/check-update` and `/refresh-from-source` paths against a stubbed-fetch scenario. To do that, since `globalThis.fetch` is invoked inside the production `skills:check-for-updates` handler, you can either:
- (a) Use `vi.spyOn(globalThis, 'fetch')` to stub the global, OR
- (b) Re-register `skills:check-for-updates` after the plugin's init to override the production handler with a mock (the bus allows re-registration in test harnesses).

Option (a) is simpler. Add:

```typescript
import { vi } from 'vitest';
// ... inside the describe block:

it('POST /admin/skills/:id/check-update reports an upgrade when remote version > current', async () => {
  const h = await makeHarness();
  const handlers = createAdminSkillsHandlers({ bus: h.bus });

  // Create a skill with a sourceUrl
  const skillMd = `---\nname: src3\ndescription: d\nversion: 1\nsourceUrl: https://example.com/src3.md\n---\nbody`;
  await handlers.create(mkReq({ body: { skillMd } }), mkRes().res);

  const remoteBody = `---\nname: src3\ndescription: d\nversion: 5\n---\nnew body`;
  const fetchSpy = vi.spyOn(globalThis, 'fetch').mockResolvedValue(
    new Response(remoteBody, { status: 200 }),
  );
  try {
    const { res, statusOf, bodyOf } = mkRes();
    await handlers.checkUpdate(mkReq({ params: { id: 'src3' } }), res);
    expect(statusOf()).toBe(200);
    const body = bodyOf() as { available: boolean; latestVersion?: number };
    expect(body.available).toBe(true);
    expect(body.latestVersion).toBe(5);
  } finally {
    fetchSpy.mockRestore();
  }
});

it('POST /admin/skills/:id/refresh-from-source upserts when available', async () => {
  const h = await makeHarness();
  const handlers = createAdminSkillsHandlers({ bus: h.bus });

  const skillMd = `---\nname: src4\ndescription: d\nversion: 1\nsourceUrl: https://example.com/src4.md\n---\nbody v1`;
  await handlers.create(mkReq({ body: { skillMd } }), mkRes().res);

  const remoteBody = `---\nname: src4\ndescription: d\nversion: 2\nsourceUrl: https://example.com/src4.md\n---\nbody v2`;
  const fetchSpy = vi.spyOn(globalThis, 'fetch').mockResolvedValue(
    new Response(remoteBody, { status: 200 }),
  );
  try {
    const { res, statusOf, bodyOf } = mkRes();
    await handlers.refresh(mkReq({ params: { id: 'src4' } }), res);
    expect(statusOf()).toBe(200);
    expect((bodyOf() as { updated: boolean }).updated).toBe(true);

    // GET reflects the new body + version
    const { res: r2, bodyOf: b2 } = mkRes();
    await handlers.get(mkReq({ params: { id: 'src4' } }), r2);
    const detail = b2() as { version: number; bodyMd: string };
    expect(detail.version).toBe(2);
    expect(detail.bodyMd).toContain('body v2');
  } finally {
    fetchSpy.mockRestore();
  }
});
```

If `Response` isn't a globally-available type in the test env, use a `{ ok: true, status: 200, text: async () => remoteBody, json: ... }` shape — but Node 20+ has `Response` globally, so it should just work.

### Verify

